const Q_GEOGRAPHY_2014=[{"id": "objective>Geography>2014>1", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which subject are you doing?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Geography</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Physics</div>", "<div style=\"font-family:Cambria;font-size:17px;\">CRK</div>", "<div style=\"font-family:Cambria;font-size:17px;\">English</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The subject being done is Geography. This is evident from the context of the question, which is categorized under Geography.</div>", "topic": "HUMAN GEOGRAPHY : POPULATION"}, {"id": "objective>Geography>2014>2", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><strong>Use the diagram below to answer this question</strong> <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/>  <br/> If the scale of the map is enlarged four times, the new scale will be</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">1:12500</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1:25000</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1:100000</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1:290000</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">1/50,000 × 4/1 = 4/50,000  <br/>  The new scale will be 1:12,500</div>", "topic": "PRATICAL GEOGRAPHY I : MAP READING AND INTERPRETATION"}, {"id": "objective>Geography>2014>3", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> <strong>Use the diagram below to answer this question</strong> <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The area marked <strong>F-E</strong> is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">an inselberg</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a cliff</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a valley</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a spur</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">It is a highland between two lowlands. It alternates with a valley.</div>", "topic": "PRATICAL GEOGRAPHY II : LANDFORMS"}, {"id": "objective>Geography>2014>4", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> <strong>Use the diagram below to answer this question</strong> <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The highest point on the map is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">340m</div>", "<div style=\"font-family:Cambria;font-size:17px;\">350m</div>", "<div style=\"font-family:Cambria;font-size:17px;\">400m</div>", "<div style=\"font-family:Cambria;font-size:17px;\">525m</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The highest point on the map is measured to about 525m.</div>", "topic": "PRATICAL GEOGRAPHY II : LANDFORMS"}, {"id": "objective>Geography>2014>5", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> <strong>Use the diagram below to answer this question</strong> <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The likely occupation of the inhabitants of Ate is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">farming </div>", "<div style=\"font-family:Cambria;font-size:17px;\">fishing</div>", "<div style=\"font-family:Cambria;font-size:17px;\">lumbering</div>", "<div style=\"font-family:Cambria;font-size:17px;\">mining</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">It will be most likely fishing and cultivation of crops which are both farming.</div>", "topic": "HUMAN GEOGRAPHY : SELECTED ECONOMIC ACTIVITIES"}, {"id": "objective>Geography>2014>6", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><strong>Use the diagram below to answer this question</strong> <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/>  <br/> The total groundnut export from 2000 to 2003 is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">1,500 metric tonnes</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1,700 metric tonnes</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1,400 metric tonnes </div>", "<div style=\"font-family:Cambria;font-size:17px;\">1,800 metric tonnes</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">300 + 300 + 400 + 500 = 1,500 metric tonnes <br/> The total groundnut export from 2000 to 2003 is 1,500 metric tonnes</div>", "topic": "HUMAN GEOGRAPHY : SELECTED ECONOMIC ACTIVITIES"}, {"id": "objective>Geography>2014>7", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> <strong>Use the diagram below to answer this question</strong> <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The total export in 2002 is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">800 metric tonnes</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1200 metric tonnes</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1000 metric tonnes</div>", "<div style=\"font-family:Cambria;font-size:17px;\">11000 metric tonnes</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">It is 1,000 metric tonnes which is the total length of the bar for the year 2002.</div>", "topic": "PRATICAL GEOGRAPHY I : INTERPRETATION OF STATISTICAL DATA; MAPS AND DIAGRAMS"}, {"id": "objective>Geography>2014>8", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In chain surveying, the basic principle is to measure </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">angles</div>", "<div style=\"font-family:Cambria;font-size:17px;\">heights</div>", "<div style=\"font-family:Cambria;font-size:17px;\">depths</div>", "<div style=\"font-family:Cambria;font-size:17px;\">distances</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Chain surveying is a type of surveying that involves the measurement of distances. It is the simplest method of surveying in which only linear measurements are made in the field. The main principle of chain surveying is to provide a framework of lines of known length and direction. The angles, heights, and depths are not the primary measurements in chain surveying.</div>", "topic": "PRATICAL GEOGRAPHY I : ELEMENTARY SURVEYING CHAIN AND PRISMATIC"}, {"id": "objective>Geography>2014>9", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of these planets completes its orbit in a much shorter space of time?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Saturn</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Jupiter</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Mercury</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Earth</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Mercury, the planet closest to the sun, completes its orbit in a much shorter space of time compared to other planets. It takes approximately 88 Earth days for Mercury to complete one full orbit around the sun. This is much shorter than the orbital periods of Saturn, Jupiter, and Earth.</div>", "topic": "PRATICAL GEOGRAPHY II : THE EARTH AS A PLANET"}, {"id": "objective>Geography>2014>10", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Shale is a fine-textured sedimentary rock formed principally from the particles of </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Sand</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Clay</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Quartz</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Calcite</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Shale is a fine-grained, clastic sedimentary rock composed of mud that is a mix of flakes of clay minerals and tiny fragments (silt-sized particles) of other minerals, especially quartz and calcite.</div>", "topic": "PRATICAL GEOGRAPHY II : ROCKS"}, {"id": "objective>Geography>2014>11", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Organic sedimentary rocks are formed from the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">solution of substances</div>", "<div style=\"font-family:Cambria;font-size:17px;\">result of pressure from underlying rocks</div>", "<div style=\"font-family:Cambria;font-size:17px;\">remains of living organisms</div>", "<div style=\"font-family:Cambria;font-size:17px;\">vegetation matters</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Organic sedimentary rocks are formed from the remains of plants and animals. These remains were once living organisms, hence the term 'organic'. They are deposited over time, often millions of years, and become compacted to form rock.</div>", "topic": "PRATICAL GEOGRAPHY II : ROCKS"}, {"id": "objective>Geography>2014>12", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The intrusive landform produced when magma is cooled within the earth surface is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">cinder cones</div>", "<div style=\"font-family:Cambria;font-size:17px;\">batholith</div>", "<div style=\"font-family:Cambria;font-size:17px;\">composite cones</div>", "<div style=\"font-family:Cambria;font-size:17px;\">geyser</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Batholith is a massive type of plutonic rock formed as a result of solidification of molten magma within the earth crust.</div>", "topic": "PRATICAL GEOGRAPHY II : ROCKS"}, {"id": "objective>Geography>2014>13", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is an agent of denudation?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Insolation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Wind</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Energy</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Gravity</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Wind aids the lowering of the earth surface especially in the desert where land surface is exposed to wind erosion.</div>", "topic": "PRATICAL GEOGRAPHY II : ROCKS"}, {"id": "objective>Geography>2014>14", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following rocks is characterized by layer formation and strata?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Metamorphic</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Volcanic</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Sedimentary</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Igneous</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Sedimentary rocks are characterized by layer formation and strata. They are formed from the accumulation of sediments such as sand, silt, and even organic material. Over time, these layers are compacted and cemented together to form rock. The layers or 'strata' are often visible in sedimentary rocks.</div>", "topic": "PRATICAL GEOGRAPHY II : ROCKS"}, {"id": "objective>Geography>2014>15", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following seas has the highest salinity?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Caspian Sea</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Mediterranean Sea</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Baltic Sea</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Red Sea</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The Red Sea has the highest salinity among the given options. Salinity refers to the amount of salts dissolved in water. The Red Sea's high salinity is due to high evaporation rates, limited freshwater inflow, and its connection to the Indian Ocean which is also high in salinity.</div>", "topic": "PRATICAL GEOGRAPHY II : WATER BODIES"}, {"id": "objective>Geography>2014>16", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Some lakes are seasonal due to their location in</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">hot deserts</div>", "<div style=\"font-family:Cambria;font-size:17px;\">humid areas</div>", "<div style=\"font-family:Cambria;font-size:17px;\">high altitude</div>", "<div style=\"font-family:Cambria;font-size:17px;\">cool temperate margin</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Some lakes are seasonal due to their location in hot deserts. In hot desert areas, lakes may form temporarily after rainfall but evaporate quickly due to the high temperatures and aridity. These are often called ephemeral lakes.</div>", "topic": "PRATICAL GEOGRAPHY II : WATER BODIES"}, {"id": "objective>Geography>2014>17", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is an element of weather?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Thunder </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Breeze</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Latitude </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Precipitation</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">An element of weather refers to the different factors that determine weather conditions. These include temperature, humidity, wind, and precipitation. Precipitation, which includes rain, snow, sleet, and hail, is therefore an element of weather. Thunder is a sound caused by lightning, breeze is a light wind, and latitude is a geographical coordinate, none of which are elements of weather.</div>", "topic": "PRATICAL GEOGRAPHY II : WEATHER AND CLIMATE"}, {"id": "objective>Geography>2014>18", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A line drawn on a map to show places of equal temperature is known as </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">isobar</div>", "<div style=\"font-family:Cambria;font-size:17px;\">isotherm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">isohyet</div>", "<div style=\"font-family:Cambria;font-size:17px;\">isoline</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Isotherm is for equal temperature, isobar is for equal pressure, isohyet for equal rainfall and isoline for equal value.</div>", "topic": "PRATICAL GEOGRAPHY II : WEATHER AND CLIMATE"}, {"id": "objective>Geography>2014>19", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The term used to describe the vegetation type of the Amazon Basin is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Pampas</div>", "<div style=\"font-family:Cambria;font-size:17px;\">coniferous</div>", "<div style=\"font-family:Cambria;font-size:17px;\">selvas</div>", "<div style=\"font-family:Cambria;font-size:17px;\">vale</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The term used to describe the vegetation type of the Amazon Basin is 'selvas'. Selvas refers to dense, generally tropical, vegetation, typically having high biodiversity. Pampas is a type of lowland area in South America, coniferous refers to trees that produce cones and have needle-like leaves, and vale is a term for a valley, none of which accurately describe the vegetation type of the Amazon Basin.</div>", "topic": "PRATICAL GEOGRAPHY II : VEGETATION"}, {"id": "objective>Geography>2014>20", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The major factor which determines the rate of infiltration of water into the sub-soil is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">rainfall intensity</div>", "<div style=\"font-family:Cambria;font-size:17px;\">temperature</div>", "<div style=\"font-family:Cambria;font-size:17px;\">nature of rocks</div>", "<div style=\"font-family:Cambria;font-size:17px;\">nature of slope</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Nature of rocks determine percolation rate. In rocks with small pore spaces, the rate is low.</div>", "topic": "PRATICAL GEOGRAPHY II : WATER BODIES"}, {"id": "objective>Geography>2014>21", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The level of development of the soil profile is determined by </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">climate</div>", "<div style=\"font-family:Cambria;font-size:17px;\">time</div>", "<div style=\"font-family:Cambria;font-size:17px;\">parent material</div>", "<div style=\"font-family:Cambria;font-size:17px;\">organic matter</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Soil organic matter (SOM) is the organic matter component of soil, consisting of plant and animal residues at various stages of decomposition, cells and tissues of soil organisms, and substances synthesized by soil organisms.</div>", "topic": "PRATICAL GEOGRAPHY II : SOILS"}, {"id": "objective>Geography>2014>22", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Volcanoes are considered natural resources because they provide</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">tourism</div>", "<div style=\"font-family:Cambria;font-size:17px;\">mountainous landscap</div>", "<div style=\"font-family:Cambria;font-size:17px;\">fertile soils</div>", "<div style=\"font-family:Cambria;font-size:17px;\">carbon dioxide</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The areas of volcanic mountains have fertile soil as a result of the rock mineral washed down or weathered.</div>", "topic": "PRATICAL GEOGRAPHY II : LANDFORMS"}, {"id": "objective>Geography>2014>23", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is a component of a biotic community?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Rocks</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Water</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Gases </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Animals</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A biotic community, also known as a biological community, is a group of organisms that interact with each other in a specific environment. This includes animals, plants, fungi, and microorganisms. Therefore, 'Animals' is the correct answer. Rocks, Water, and Gases are abiotic components, meaning they are non-living physical and chemical elements in an ecosystem.</div>", "topic": "PRATICAL GEOGRAPHY II : ROCKS"}, {"id": "objective>Geography>2014>24", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The type of coal that burns with great heat and very little smoke is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">anthracite </div>", "<div style=\"font-family:Cambria;font-size:17px;\">lignite</div>", "<div style=\"font-family:Cambria;font-size:17px;\">steam coal</div>", "<div style=\"font-family:Cambria;font-size:17px;\">peat</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The best type of coal is anthracite. It is the hardest with high hydrocarbon content and it is practically smokeless.</div>", "topic": "PRATICAL GEOGRAPHY II : ROCKS"}, {"id": "objective>Geography>2014>25", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The most serious environmental effect posed by hazardous wastes is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">contamination of ground water</div>", "<div style=\"font-family:Cambria;font-size:17px;\">destruction of habitat</div>", "<div style=\"font-family:Cambria;font-size:17px;\">air pollution</div>", "<div style=\"font-family:Cambria;font-size:17px;\">increased use for land to landfills</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Air pollution spreads wider and faster than any other form of pollution.</div>", "topic": "PRATICAL GEOGRAPHY II : ENVIRONMENTAL HAZARDS"}, {"id": "objective>Geography>2014>26", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following indices is a measure of development?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Total population</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Population density</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Life expectancy</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Types of building</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Life expectancy is a measure of development. It is an average estimate of how long a person is expected to live. This is based on the year of their birth, their current age, and other demographic factors including their gender. Higher life expectancy usually indicates better healthcare and living conditions, which are indicators of development. The other options like total population, population density, and types of building are not direct measures of development.</div>", "topic": "HUMAN GEOGRAPHY : SELECTED ECONOMIC ACTIVITIES"}, {"id": "objective>Geography>2014>27", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The growth rate of population is determined by </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">improved agriculture </div>", "<div style=\"font-family:Cambria;font-size:17px;\">number of death per 1000</div>", "<div style=\"font-family:Cambria;font-size:17px;\">birth and death rates</div>", "<div style=\"font-family:Cambria;font-size:17px;\">technological know-how</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The growth rate of a population is determined by the birth and death rates. It is calculated by subtracting the death rate from the birth rate. The other options like improved agriculture and technological know-how can indirectly affect the population growth rate by improving living conditions and thus potentially increasing birth rates and decreasing death rates, but they are not direct determinants of population growth rate.</div>", "topic": "HUMAN GEOGRAPHY : POPULATION"}, {"id": "objective>Geography>2014>28", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A population problem faced by some developed countries today is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">very slow replacement rate</div>", "<div style=\"font-family:Cambria;font-size:17px;\">over population</div>", "<div style=\"font-family:Cambria;font-size:17px;\">high death rate</div>", "<div style=\"font-family:Cambria;font-size:17px;\">high dependency ratio</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In developed nations, the lower dependency class(children) is always very small while the working class(16 - 64) is always very large, so there is the problem of replacing the working class. That is why developed nations are turning to Africa for workforce.</div>", "topic": "HUMAN GEOGRAPHY : POPULATION"}, {"id": "objective>Geography>2014>29", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is a favourable condition for settlement site?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Dense natural vegetation </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Marshy Fadama area</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Adequate water supply </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Mountainous Area</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Adequate water supply is a favourable condition for settlement site. Water is a basic necessity for human survival. It is used for drinking, cooking, washing, and irrigation of farms. Therefore, areas with adequate water supply are often chosen as settlement sites. Dense natural vegetation, marshy Fadama area, and mountainous areas are not ideal for settlement because they present challenges such as difficulty in clearing the land for building and farming, poor drainage and difficult accessibility.</div>", "topic": "HUMAN GEOGRAPHY : SETTLEMENT"}, {"id": "objective>Geography>2014>30", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following countries is perennial irrigation extensively practised?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">India</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Bangladesh</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The Sudan </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Holland</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The Sudan is located in the desert and as such perennial irrigation is extensively practised.</div>", "topic": "REGIONAL GEOGRAPHY : IRRIGATION AGRICULTURE IN THE NILE AND NIGER BASIN"}, {"id": "objective>Geography>2014>31", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Dispersed rural settlements are most likely to be found in areas with</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">limited agricultural land and poor surface drainage</div>", "<div style=\"font-family:Cambria;font-size:17px;\">abundant agricultural land and good surface drainage</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a large agricultural population and restricted accessibility </div>", "<div style=\"font-family:Cambria;font-size:17px;\">a small agricultural population and poor surface drainage</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Each farmer takes portion of land for his farming and keeps a distance from another farm but if the land is limited, the farms get clustered together.</div>", "topic": "HUMAN GEOGRAPHY : SETTLEMENT"}, {"id": "objective>Geography>2014>32", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Dairy farming is an example of intensive farming commonly practised in </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Brazil</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Denmark</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Spain</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Niger</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Intensive farming refers to a type of agriculture, both of crop plants and of animals, with higher levels of input and output per cubic unit of agricultural land area. Denmark is known for its dairy farming due to its favourable climate and advanced technology in dairy farming.</div>", "topic": "HUMAN GEOGRAPHY : SELECTED ECONOMIC ACTIVITIES"}, {"id": "objective>Geography>2014>33", "question": "<div style=\"font-family:Cambria;font-size:17px;\">As a country, a smaller percentage of the workforce tend to be employed in </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">mining</div>", "<div style=\"font-family:Cambria;font-size:17px;\">agriculture</div>", "<div style=\"font-family:Cambria;font-size:17px;\">manufacturing</div>", "<div style=\"font-family:Cambria;font-size:17px;\">services</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">When a large percentage of the workforce is engaged in agriculture, such a nation is termed a developing nation.</div>", "topic": "HUMAN GEOGRAPHY : SELECTED ECONOMIC ACTIVITIES"}, {"id": "objective>Geography>2014>34", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Developing countries mostly engage in primary economic activities because of </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">underdevelopment</div>", "<div style=\"font-family:Cambria;font-size:17px;\">interdependence</div>", "<div style=\"font-family:Cambria;font-size:17px;\">overdependence</div>", "<div style=\"font-family:Cambria;font-size:17px;\">colonization</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Primary economic activities are those that involve the extraction of raw materials from the earth. These activities are the most basic form of economic activity and are often the first to develop in a country. Developing countries often have a high percentage of their workforce engaged in these activities due to a lack of development in other sectors of the economy.</div>", "topic": "HUMAN GEOGRAPHY : SELECTED ECONOMIC ACTIVITIES"}, {"id": "objective>Geography>2014>35", "question": "<div style=\"font-family:Cambria;font-size:17px;\">High annual rainfall of at least 1520mm well distributed throughout the year with the heaviest during growing season is most suitable for the production of </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">wheat</div>", "<div style=\"font-family:Cambria;font-size:17px;\">maize</div>", "<div style=\"font-family:Cambria;font-size:17px;\">barley</div>", "<div style=\"font-family:Cambria;font-size:17px;\">rice</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Rice is the crop that requires high annual rainfall of at least 1520mm well distributed throughout the year with the heaviest during growing season. Rice is a water-intensive crop and thrives in areas with high rainfall.</div>", "topic": "PRATICAL GEOGRAPHY II : VEGETATION"}, {"id": "objective>Geography>2014>36", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The main factor influencing the location of manufacturing industries in West Africa is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">good transportation network</div>", "<div style=\"font-family:Cambria;font-size:17px;\">rapid population growth</div>", "<div style=\"font-family:Cambria;font-size:17px;\">adequate physical development</div>", "<div style=\"font-family:Cambria;font-size:17px;\">nearness to raw materials</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The main factor influencing the location of manufacturing industries in West Africa is nearness to raw materials. Industries are usually located near the source of raw materials to reduce the cost of transportation and ensure a steady supply of materials.</div>", "topic": "HUMAN GEOGRAPHY : SELECTED ECONOMIC ACTIVITIES"}, {"id": "objective>Geography>2014>37", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An agricultural practice that allows a wide range of crops to be grown without fallowing is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">shifting cultivation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">crop rotation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">mixed cropping</div>", "<div style=\"font-family:Cambria;font-size:17px;\">intensive cultivation</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">It allows wide range of crops without fallowing. A land is divided into different portions with each producing different crops and is subjected to rotation yearly.</div>", "topic": "PRATICAL GEOGRAPHY II : VEGETATION"}, {"id": "objective>Geography>2014>38", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Arable farming and animal husbandry widely practised in Britain and many parts of Europe is referred to as </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">mixed farming </div>", "<div style=\"font-family:Cambria;font-size:17px;\">crop farming</div>", "<div style=\"font-family:Cambria;font-size:17px;\">orchard farming</div>", "<div style=\"font-family:Cambria;font-size:17px;\">pastoral farming</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Arable farming and animal husbandry widely practised in Britain and many parts of Europe is referred to as mixed farming. Mixed farming is a type of farming which involves both the growing of crops as well as the raising of livestock. The aim is to increase income through different sources and to complement the enterprises in terms of labor utilization and production.</div>", "topic": "HUMAN GEOGRAPHY : SELECTED ECONOMIC ACTIVITIES"}, {"id": "objective>Geography>2014>39", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><strong>Use the diagram below to answer this question</strong> <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/>  <br/> The area marked <strong>P</strong> is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Udi Plateau</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Oban Hills</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Western Uplands</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Obudu Plateau</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The highlands of Western Nigeria. The area marked <strong>P</strong> is Western Uplands.</div>", "topic": "PRATICAL GEOGRAPHY II : LANDFORMS"}, {"id": "objective>Geography>2014>40", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> <strong>Use the diagram below to answer this question</strong> <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The area marked N is over </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">900m</div>", "<div style=\"font-family:Cambria;font-size:17px;\">800m</div>", "<div style=\"font-family:Cambria;font-size:17px;\">700m</div>", "<div style=\"font-family:Cambria;font-size:17px;\">600m</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Adamawa Plateau is between 1,800 and 2,400m above sea level.</div>", "topic": "PRATICAL GEOGRAPHY II : LANDFORMS"}, {"id": "objective>Geography>2014>41", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The type of vegetation found on the Mambila Plateau is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">guinea savanna </div>", "<div style=\"font-family:Cambria;font-size:17px;\">sudan savanna</div>", "<div style=\"font-family:Cambria;font-size:17px;\">high forest</div>", "<div style=\"font-family:Cambria;font-size:17px;\">montane</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Montane Vegetation is found on the high plateau. The type of vegetation found on the Mambila Plateau is high forest.</div>", "topic": "PRATICAL GEOGRAPHY II : VEGETATION"}, {"id": "objective>Geography>2014>42", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following best explains the reason for the decrease in the practice of bush fallowing in Nigeria?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Mechanized Farming </div>", "<div style=\"font-family:Cambria;font-size:17px;\">The availability of agricultural inputs</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Rapid growth of population</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Lack of interest in crop production</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The decrease in the practice of bush fallowing in Nigeria is best explained by the rapid growth of population. Bush fallowing is a traditional method of farming where a piece of land is cleared and cultivated for a period of time and then left to regain its fertility naturally. However, with the rapid growth of population, there is increased demand for land for housing and other uses, reducing the amount of land available for bush fallowing.</div>", "topic": "HUMAN GEOGRAPHY : SELECTED ECONOMIC ACTIVITIES"}, {"id": "objective>Geography>2014>43", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Secondary economic activities are those that involve the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">packaging of finished goods</div>", "<div style=\"font-family:Cambria;font-size:17px;\">distribution of raw materials</div>", "<div style=\"font-family:Cambria;font-size:17px;\">distribution of finished goods</div>", "<div style=\"font-family:Cambria;font-size:17px;\">processing of raw materials</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Secondary economic activities involve the processing of raw materials into finished goods. This includes activities such as manufacturing, processing, and construction. The other options involve either the distribution or packaging of goods, which are considered tertiary activities as they do not involve the transformation of raw materials.</div>", "topic": "HUMAN GEOGRAPHY : SELECTED ECONOMIC ACTIVITIES"}, {"id": "objective>Geography>2014>44", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The reason for seasonal migration of nomadic herdsmen is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">for the search of water and good grazing</div>", "<div style=\"font-family:Cambria;font-size:17px;\">because of the inability of government to provide shelter</div>", "<div style=\"font-family:Cambria;font-size:17px;\">to search for a safe environment </div>", "<div style=\"font-family:Cambria;font-size:17px;\">due to high rainfall in some regions</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Nomadic herdsmen migrate seasonally primarily in search of water and good grazing for their livestock. This is because the availability of these resources varies with the seasons. The other options do not accurately describe the primary reasons for the seasonal migration of nomadic herdsmen.</div>", "topic": "HUMAN GEOGRAPHY : POPULATION"}, {"id": "objective>Geography>2014>45", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The main industry associated with the Ruhr Valley region is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Iron and steel</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Oil refining</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Food manufacturing</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Ship building</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The Ruhr Valley region in Germany is known for its iron and steel industry. It is one of the largest industrial regions in Europe and has a high concentration of heavy industry, including iron and steel production. The other options do not accurately represent the main industry associated with the Ruhr Valley region.</div>", "topic": "HUMAN GEOGRAPHY : SELECTED ECONOMIC ACTIVITIES"}, {"id": "objective>Geography>2014>46", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following factors influenced the growth of the Ruhr Valley?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Soil fertility</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Good climate</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Agriculture</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Industrialization</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The Ruhr Valley in Germany is known for its industrial development rather than its agricultural potential. The region is rich in coal, which was a key factor in its industrialization during the 19th and 20th centuries. Therefore, the factor that influenced the growth of the Ruhr Valley is 'Industrialization'.</div>", "topic": "HUMAN GEOGRAPHY : SELECTED ECONOMIC ACTIVITIES"}, {"id": "objective>Geography>2014>47", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The largest producer of timber in Africa is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Kenya</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Senegal </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Cote'd Ivoire</div>", "<div style=\"font-family:Cambria;font-size:17px;\">South Africa</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Cote d'Ivoire is the largest producer of timber in Africa. The country has a significant forest cover and has a well-developed timber industry. Therefore, the correct answer is 'Cote'd Ivoire'.</div>", "topic": "REGIONAL GEOGRAPHY : LUMBERING IN EQUATORIAL AFRICA"}, {"id": "objective>Geography>2014>48", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The relatively low level of rail transport development in tropical Africa has</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">encouraged the development of airports</div>", "<div style=\"font-family:Cambria;font-size:17px;\">reduced government expenditure on transportation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">placed undue pressure on roads</div>", "<div style=\"font-family:Cambria;font-size:17px;\">increased the rate of migration from the sea</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The relatively low level of rail transport development in tropical Africa has placed undue pressure on roads. This is because the lack of a well-developed rail network means that most goods and passengers have to be transported by road, which can lead to congestion and increased wear and tear on the roads. Therefore, the correct answer is 'placed undue pressure on roads'.</div>", "topic": "REGIONAL GEOGRAPHY : TRANSPORTATION IN AFRICA"}, {"id": "objective>Geography>2014>49", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The high population density in the Nile Valley is as a result of </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">industrial growth in the valley</div>", "<div style=\"font-family:Cambria;font-size:17px;\">multipurpose dams to support growing population</div>", "<div style=\"font-family:Cambria;font-size:17px;\">transportation development</div>", "<div style=\"font-family:Cambria;font-size:17px;\">shaduf irrigation</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Perennial irrigation system where water is stored in dams for the planting season.</div>", "topic": "HUMAN GEOGRAPHY : POPULATION"}, {"id": "objective>Geography>2014>50", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following population characteristics is best related to African countries?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Low birth rate and low death rate</div>", "<div style=\"font-family:Cambria;font-size:17px;\">High birth rate and low death rate</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Low birth rate and high death rate</div>", "<div style=\"font-family:Cambria;font-size:17px;\">High birth rate and high death rate</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Religion and culture encourage high birth rate while improved medical care has reduced death rate leading to high population in Africa.</div>", "topic": "HUMAN GEOGRAPHY : POPULATION"}];
